/* Centroid calculator */
function centroid(path){const nums=path.replace(/[MLZHVCSQTA]/gi," ").trim().split(/[\s,]+/).map(Number).filter(n=>!isNaN(n));let cx=0,cy=0,n=0;for(let i=0;i<nums.length;i+=2){cx+=nums[i];cy+=nums[i+1];n++;}return n?[cx/n,cy/n]:[0,0];}

/* ═══ SVG MAP ═══ */
function IndiaMap({mode,selectedId,hovId,onSelect,onHover,P}){
  const isLang=mode==="language";const isRegion=mode==="region";
  const stateIds=Object.keys(PATHS).filter(id=>STATES_META[id]);
  return(
    <svg viewBox="0 0 480 560" style={{width:"100%",maxWidth:420,display:"block",margin:"0 auto"}}>
      <rect width="480" height="560" fill="transparent"/>
      {stateIds.map(id=>{
        const meta=STATES_META[id];const data=STATE_DATA[id];if(!meta)return null;
        const path=PATHS[id];if(!path||path.length<20)return null;
        const isSel=selectedId===id||(isRegion&&selectedId===meta.region);
        const isHov=hovId===id;const has=data?.c>0;
        const baseColor=isLang?(LC[meta.lang]||P.mute):RC[meta.region];
        const intensity=has?Math.min(0.12+(data.c/3)*0.3,0.45):0.03;
        const fillOp=isSel?0.5:(isHov?0.35:(has?intensity:0.03));
        const strokeOp=isSel?0.8:(isHov?0.5:(has?0.25:0.08));
        const [cx,cy]=centroid(path);
        const showLabel=isSel||isHov||["rj","up","mp","mh","gj","ka","tn","ap","wb","or","as","jk","ct","br","jh","kl","hr","pb"].includes(id);
        return(<g key={id} onClick={()=>onSelect(isRegion?meta.region:id)} onMouseEnter={()=>onHover(id)} onMouseLeave={()=>onHover(null)} style={{cursor:"pointer"}}>
          <path d={path} fill={baseColor} fillOpacity={fillOp} stroke={baseColor} strokeOpacity={strokeOp} strokeWidth={isSel?1.8:isHov?1.2:0.6} style={{transition:"all 0.2s",filter:isSel?`drop-shadow(0 0 6px ${baseColor}40)`:""}}/>
          {showLabel&&<text x={cx} y={cy} textAnchor="middle" dominantBaseline="central" fill={isSel||isHov?"#fff":P.sub} fontSize={isSel?9:7.5} fontWeight={isSel?700:500} fontFamily="'Sora'" style={{pointerEvents:"none",textShadow:isSel?`0 0 4px ${P.bg}`:""}}>{id.toUpperCase()}</text>}
          {has&&!isSel&&<><circle cx={cx+14} cy={cy-10} r={6.5} fill={baseColor} opacity={0.9} style={{pointerEvents:"none"}}/><text x={cx+14} y={cy-10} textAnchor="middle" dominantBaseline="central" fill="#fff" fontSize={7} fontWeight={700} fontFamily="'Sora'" style={{pointerEvents:"none"}}>{data.c}</text></>}
        </g>);
      })}
    </svg>);
}

