function CampCard({c,i,onClick,P}){
  const pc={brief:P.mute,shortlist:P.amber,production:P.accent,live:P.green,completed:P.doneTxt};
  return(<div className="au" onClick={onClick} style={{animationDelay:`${i*40}ms`,background:P.surface,border:`1px solid ${P.border}`,borderRadius:9,padding:"11px 13px",marginBottom:6,cursor:"pointer",transition:"all 0.2s",opacity:c.p==="completed"?0.5:1}} onMouseOver={e=>{e.currentTarget.style.borderColor=`${P.accent}30`;e.currentTarget.style.transform="translateX(2px)";}} onMouseOut={e=>{e.currentTarget.style.borderColor=P.border;e.currentTarget.style.transform="none";}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}><div><h4 style={{margin:0,fontSize:12,fontWeight:500,color:P.white,fontFamily:"'Sora'"}}>{c.n}</h4><span style={{fontSize:8,color:P.accent,textTransform:"uppercase"}}>{c.s}</span></div>
      <div style={{display:"flex",alignItems:"center",gap:4}}><Dot color={pc[c.p]||P.mute}/><span style={{fontSize:9,color:P.sub}}>{PL[c.p]}</span><span style={{fontSize:9,fontWeight:600,color:pc[c.p]}}>{c.pr}%</span></div></div>
    <div style={{display:"flex",gap:12,alignItems:"center"}}>{[["Reach",c.r],["Budget",c.b]].map(([l,v])=><div key={l}><div style={{fontSize:7,color:P.mute,textTransform:"uppercase",letterSpacing:"0.1em",fontWeight:600}}>{l}</div><div style={{fontSize:11.5,fontWeight:600,color:v==="—"?P.doneTxt:P.text,marginTop:1}}>{v}</div></div>)}<span style={{marginLeft:"auto",fontSize:8.5,color:P.accent,fontWeight:500}}>View →</span></div>
  </div>);
}

