/* ═══ LANGUAGE PANEL ═══ */
function LangPanel({P}){
  const g={};Object.entries(STATES_META).forEach(([id,m])=>{const d=STATE_DATA[id];if(!g[m.lang])g[m.lang]={states:[],c:0,cr:0};g[m.lang].states.push(m.name);g[m.lang].c+=d.c;g[m.lang].cr+=d.cr;});
  const sorted=Object.entries(g).sort((a,b)=>b[1].c-a[1].c);
  return(<div><div style={{fontSize:8.5,color:P.mute,textTransform:"uppercase",letterSpacing:"0.08em",fontWeight:600,marginBottom:8}}>Language Distribution</div>
    {sorted.map(([lang,d],i)=><div key={lang} className="au" style={{animationDelay:`${i*25}ms`,background:P.surface,border:`1px solid ${P.border}`,borderRadius:8,padding:"9px 12px",marginBottom:5,display:"flex",alignItems:"center",gap:9}}>
      <Dot color={LC[lang]||P.mute} sz={7}/><div style={{flex:1}}><div style={{fontSize:11.5,fontWeight:600,color:P.text}}>{lang}</div><div style={{fontSize:8.5,color:P.sub,marginTop:1}}>{d.states.slice(0,4).join(", ")}{d.states.length>4?"...":""}</div></div>
      <div style={{textAlign:"right"}}><div style={{fontSize:13,fontWeight:700,color:d.c?P.accent:P.doneTxt}}>{d.c}</div><div style={{fontSize:7,color:P.mute,textTransform:"uppercase"}}>campaigns</div></div>
      <div style={{textAlign:"right"}}><div style={{fontSize:13,fontWeight:700,color:d.cr?P.green:P.doneTxt}}>{d.cr}</div><div style={{fontSize:7,color:P.mute,textTransform:"uppercase"}}>creators</div></div>
    </div>)}
  </div>);
}

